import React from "react";
import "../styles/contact.css";
import "../index.css";
import Header from "../components/Header.js"
import Footer from "../components/Footer.js"
import polarBear1 from '../images/portfolioImages/polarBear1.png';
import polarBear2 from '../images/portfolioImages/polarBear2.png';
import polarBear3 from '../images/portfolioImages/polarbear3.png';
import polarBear4 from '../images/portfolioImages/polarBear4.png';


const portfolio = [
    {
        title: "Polar Bear Game & Website",
        date: "Summer 2018",
        description: "For my final project in Girls Who Code, my group and I designed a game and website to bring awareness to polar bears. We used Java, HTML, CSS, and JavaScript.",
        images: [polarBear1, polarBear2, polarBear3, polarBear4],
    }
]
class Portfolio extends React.Component {

    renderPortfolio() {
        let filmCards = filmDetails.map((content) => {
            return <FilmCard film={content.film} url={content.url} image={content.image} date={content.date} reviewp1={content.reviewp1} reviewp2={content.reviewp2} reviewp3={content.reviewp3} reviewp4={content.reviewp4} reviewp5={content.reviewp5}/>
        });

        return (
          <>
              {filmCards}
          </>
        );
      }



    render() {
        return (
            <div id="contact" className="page">
                <Header />


                <Footer />
            </div>

        );
    }
}

export default Portfolio;
